#include "pytorch_npu_helper.hpp"

static inline at::Tensor npu_conv2d_then_double_mish(const at::Tensor& conv_out) {
    at::Tensor result = at::empty_like(conv_out);
    // Custom AscendC kernel only expects a single tensor input (conv output) and produces y
    EXEC_NPU_CMD(aclnnConv2dMishMishCustom, conv_out, result);
    return result;
}

at::Tensor conv2d_mish_mish_impl(const at::Tensor& x,
                                 const at::Tensor& weight,
                                 c10::optional<at::Tensor> bias_opt) {
    // Perform conv2d with stride=1, padding=0, dilation=1, groups=1 as in the model
    at::IntArrayRef stride({1, 1});
    at::IntArrayRef padding({0, 0});
    at::IntArrayRef dilation({1, 1});
    int64_t groups = 1;
    at::Tensor conv_out = at::conv2d(x, weight, bias_opt, stride, padding, dilation, groups);
    return npu_conv2d_then_double_mish(conv_out);
}

